            if 'results' in data:
                all_results.update(data['results'])
            elif 'IDEX_result' in data:
                all_results['IDEX'] = data['IDEX_result']
    except:
        pass

# Also add individual results
try:
    # Add BCLI
    bcli_data = locals()['var_functions.execute_python:164']
    all_results['BCLI'] = {
        'company_name': 'Brainstorm Cell Therapeutics',
        'high_volatility_days': bcli_data['BCLI_high_vol_days'],
        'total_days': bcli_data['BCLI_total_days']
    }
